module top_module(
    input wire clk_in,
    output[1:0] count_out
    );reg[1:0] count = 0;  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk_in or posedge dbg_halt)
        begin
        count <= (count == 2)? 0: count + 1; 
        end
    assign count_out = count; 
endmodule
